import java.util.stream.*;
public class FlatMapDemo {
    public static void main(String[] args) {
        java.util.List<java.util.List<Integer>> nested =
            java.util.List.of(java.util.List.of(1,2,3), java.util.List.of(4,5), java.util.List.of(6));
        int sum = nested.stream()
            .flatMap(java.util.Collection::stream)
            .mapToInt(Integer::intValue)
            .sum();
        System.out.println(sum);
        long count = nested.stream().flatMap(java.util.Collection::stream).count();
        System.out.println(count);
    }
}
